window.addEventListener("scroll",()=>{let e=document.querySelector(".nav").getBoundingClientRect().top,t=document.querySelector(".sec1").getBoundingClientRect().top,n=document.querySelector(".sec2").getBoundingClientRect().top,o=document.querySelector(".sec3").getBoundingClientRect().top;document.querySelectorAll(".nav-link").forEach(i=>{e>t&&e<n?i.classList.add("sect1"):i.classList.remove("sect1"),e>n&&e<o?i.classList.add("sect2"):i.classList.remove("sect2")})});let strip=document.querySelector(".strip__fill"),windowHeight=window.innerHeight;function changeActiveNavPosition(){let e=document.querySelector("body").offsetHeight-windowHeight,t=window.pageYOffset/e*100+"%";strip.style.width=t}window.addEventListener("scroll",e=>{changeActiveNavPosition()});let nav=document.querySelector(".nav");function getCoords(e){return{top:e.getBoundingClientRect().top+pageYOffset}}const getCordT=getCoords(nav).top;let stickyNav=function(){let e=window.pageYOffset;getCordT<=e?nav.classList.add("sticky"):nav.classList.remove("sticky")};stickyNav(),window.addEventListener("scroll",()=>{stickyNav()});let scroll_top=window.pageYOffset,is_hidden=!1,enabled=!0,headerT=document.querySelector(".header");window.addEventListener("scroll",(function(e){let t=window.pageYOffset,n=headerT.clientHeight;move_down=t>scroll_top,move_down?!is_hidden&&t>n&&(is_hidden=!0,headerT.classList.add("hide")):is_hidden&&enabled&&(is_hidden=!1,headerT.classList.remove("hide")),scroll_top=t}));